/// 启动埋点上报能力；如果冷启动时已经恢复出足够的累计时长，会立即补发一次 heartbeat。
+ (void)startReporting {
    NSLog(@"EventManager startReporting. hbrate:%d, lograte:%d", WBEventManager.defaultManager.heartbeatInterval, WBEventManager.defaultManager.reportInterval);
    // 旧逻辑：
    // [[WBEventManager defaultManager] setEnabled:TRUE];
    WBEventManager *manager = [WBEventManager defaultManager];
    [manager setEnabled:TRUE];
    dispatch_async(manager.queue, ^{
        [manager reportHeartbeatIfNeeded];
    });
}

