/// 热启动回前台时，先补算后台挂起区间，再判断是否需要立刻发 heartbeat。
+ (void)syncUsageOnAppEnterForeground {
    WBEventManager *manager = [WBEventManager defaultManager];
    CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
    __block BOOL shouldFlushHeartbeatImmediately = NO;
    dispatch_sync(manager.queue, ^{
        // 旧逻辑：
        // [manager applyBackgroundUsageAtTime:now];
        // [manager persistUsageState];
        // [manager reportHeartbeatIfNeeded];
        // 先把后台挂起区间补算回来；只有“回前台补算后达阈值”的 heartbeat 才立刻 flush。
        [manager applyBackgroundUsageAtTime:now];
        if ([manager shouldReportHeartbeat]) {
            [manager doHeartBeatWithUsageReport];
            shouldFlushHeartbeatImmediately = YES;
        } else {
            [manager persistUsageState];
        }
    });
    // 让 heartbeat 先按原方式入队，再立刻触发一次批量发送，避免它继续等待后续 reportInterval。
    if (shouldFlushHeartbeatImmediately) {
        [manager flushEventListImmediately];
    }
}

